PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?attendance WHERE {
  VALUES ?series {
    wd:Q56692089 wd:Q14870260 wd:Q3511178
  }
  ?series wdt:P929 ?game .
  {
    ?game wdt:P2015 wd:Q426350
  } UNION {
    ?game wdt:P2016 wd:Q426350
  }
  ?game wdt:P4966 ?attendance .
}
ORDER BY ?attendance
OFFSET 4
LIMIT 1

